mapper.select:
SELECT ,
       p.patient_name, p.patient_no, du.real_name AS doctor_name
FROM prescription pr
LEFT JOIN patient p ON pr.patient_id = p.patient_id
LEFT JOIN sys_user du ON pr.doctor_id = du.user_id

    AND pr.status = #{status}
    AND pr.patient_id = #{patientId}
    AND pr.doctor_id = #{doctorId}

ORDER BY pr.create_time DESC
